        nonlocal max_length, min_nodes
        if len(seen) == 2 and nums[node] in seen:
            return 0
        if len(seen) > 2:
            return float('-inf')

        max_path = 0
        for neighbor in graph[node]:
            if neighbor not in path:
                new_path = dfs(neighbor, path + [node], seen | {nums[node]})
