def longestSpecialPath(nums, edges):
    n = len(nums)
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(node, parent, seen):
        max_len, min_nodes = 0, 0
        path = []
        for child in graph[node]:
            if child != parent:
                child_len, child_nodes = dfs(child, node, seen.copy())
                if child_len > max_len or (child_len == max_len and child_nodes < min_nodes):
                    max_len, min_nodes = child_len, child_nodes
                path.extend(child_nodes)

        if nums[node] in seen:
            path.append(node)
        else:
            seen.add(nums[node])
            path.append(node)

        return max_len + 1, [node] if len(seen) <= 2 else path

    _, result = dfs(0, -1, set())
    return [max_len + 1, len(result)]

