def longestSpecialPath(nums):
    n = len(nums)
    graph = [[] for _ in range(n)]
    for i in range(1, n):
        graph[nums[i]].append(i)

    def dfs(node):
        if not graph[node]:
            return [0]

        paths = []
        for child in graph[node]:
            for path in dfs(child):
                if abs(nums[child] - nums[node]) <= 1:
                    paths.append(path + 1)
                else:
                    paths.append(1)

        if paths:
            max_len = max(paths)
            min_nodes = min([p for p in paths if p == max_len])
            return [max_len, min_nodes]
        else:
            return [0]

    ans = dfs(0)
    return ans

