def longestSpecialPath(nums):
    n = len(nums)
    adj_list = [[] for _ in range(n)]
    for i in range(n):
        for j in range(i+1, n):
            if abs(nums[i] - nums[j]) <= 1:
                adj_list[i].append(j)
                adj_list[j].append(i)

    def dfs(node, visited, path, max_length, min_nodes):
        visited.add(node)
        path.append(nums[node])
        if len(set(path)) > 2:
            path.pop()
            return max_length, min_nodes

        curr_max_length = len(path)
        if curr_max_length > max_length:
            max_length = curr_max_length
            min_nodes = len(path)

        for neighbor in adj_list[node]:
            if neighbor not in visited:
                max_length, min_nodes = dfs(neighbor, visited, path, max_length, min_nodes)

        path.pop()
        return max_length, min_nodes

    max_length = 0
    min_nodes = float('inf')
    for i in range(n):
        visited = set()
        max_length, min_nodes = dfs(i, visited, [], max_length, min_nodes)

    return max_length, min_nodes
